import { cacheTag } from 'next/cache'

export async function getAllProducts() {
  'use cache'
  cacheTag('products')

  // Simulate database delay
  await new Promise((resolve) => setTimeout(resolve, 100))

  return [
    { id: 1, name: 'Laptop', price: 999 },
    { id: 2, name: 'Phone', price: 699 },
    { id: 3, name: 'Tablet', price: 499 },
    { id: 4, name: 'Headphones', price: 199 },
    { id: 5, name: 'Watch', price: 299 },
  ]
}

export async function syncProductsFromERP() {
  // Simulate a background ERP/PIM sync operation
  // In production this would call external APIs, transform data, etc.
  await new Promise((resolve) => setTimeout(resolve, 2000))
  return { synced: true, timestamp: new Date().toISOString() }
}

import { revalidateTag } from 'next/cache'
import { getAllProducts, syncProductsFromERP } from '@/lib/db'

export const metadata = {
  title: 'Product Catalog — Admin',
}

export default async function AdminProductsPage() {
  async function syncCatalog(formData: FormData) {
    'use server'

    // Kick off the ERP/PIM sync without blocking the response.
    // In production this would enqueue a background job;
    // the admin can keep working while the sync completes.
    syncProductsFromERP().catch(console.error)

    // Mark the "products" cache tag as stale.
    // The next visit to any view tagged "products" will serve
    // stale data immediately while fresh data loads in the
    // background (stale-while-revalidate).
    revalidateTag('products', 'max')
  }

  const products = await getAllProducts()

  return (
    <div style={{ maxWidth: 800, margin: '0 auto', padding: 24, fontFamily: 'system-ui, sans-serif' }}>
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 24,
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: 24 }}>Product Catalog</h1>
          <p style={{ margin: '4px 0 0', color: '#666', fontSize: 14 }}>
            {products.length} product{products.length === 1 ? '' : 's'}
          </p>
        </div>

        <form action={syncCatalog}>
          <button
            type="submit"
            style={{
              padding: '8px 16px',
              fontSize: 14,
              fontWeight: 600,
              border: '1px solid #2563eb',
              borderRadius: 6,
              background: '#2563eb',
              color: '#fff',
              cursor: 'pointer',
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <table
        style={{
          width: '100%',
          borderCollapse: 'collapse',
          fontSize: 14,
        }}
      >
        <thead>
          <tr style={{ borderBottom: '2px solid #e5e7eb', textAlign: 'left' }}>
            <th style={{ padding: '8px 12px', fontWeight: 600 }}>ID</th>
            <th style={{ padding: '8px 12px', fontWeight: 600 }}>Name</th>
            <th style={{ padding: '8px 12px', fontWeight: 600, textAlign: 'right' }}>Price</th>
          </tr>
        </thead>
        <tbody>
          {products.length === 0 ? (
            <tr>
              <td colSpan={3} style={{ padding: 24, textAlign: 'center', color: '#999' }}>
                No products found.
              </td>
            </tr>
          ) : (
            products.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: '1px solid #e5e7eb' }}
              >
                <td style={{ padding: '10px 12px', color: '#666' }}>{product.id}</td>
                <td style={{ padding: '10px 12px', fontWeight: 500 }}>{product.name}</td>
                <td style={{ padding: '10px 12px', textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                  ${product.price.toFixed(2)}
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  )
}

